// Prepare keywords for rotation and research
const config = $input.first().json;
const allKeywords = config.keywords.split(', ');

// Load history from workflow static data
const staticData = $getWorkflowStaticData('global');
const history = staticData.contentHistory || [];
const usedKeywords = history.slice(-8).map(h => h.keyword);
const usedTitles = history.slice(-4).map(h => h.title);
const usedAngles = history.slice(-4).map(h => h.angle);
const usedStoryUrls = history.slice(-4).flatMap(h => h.storyUrls || []);

// Keyword variants for expansion
const variants = ['trends 2026', 'for small business', 'cost', 'vs alternative', 'best practices', 'ROI', 'case study', 'how to'];

// Expand keyword pool
const expandedKeywords = [];
for (const kw of allKeywords) {
  expandedKeywords.push(kw);
  for (const v of variants.slice(0, 3)) {
    expandedKeywords.push(`${kw} ${v}`);
  }
}

// Rotate primary keyword (avoid last 8)
const availableKeywords = allKeywords.filter(k => !usedKeywords.includes(k));
const primaryKeyword = availableKeywords.length > 0 
  ? availableKeywords[Math.floor(Math.random() * availableKeywords.length)]
  : allKeywords[Math.floor(Math.random() * allKeywords.length)];

// Question prefixes rotation
const prefixes = [
  'what is', 'how to', 'why', 'best', 'top', 'how much does',
  'is it worth', 'when to use', 'who needs', 'where to find',
  'what are the benefits of', 'how does'
];
const runCount = history.length;
const questionPrefix = prefixes[runCount % prefixes.length];
const questionQuery = `${questionPrefix} ${primaryKeyword}`;

// Article structures rotation
const structures = ['deep-dive', 'problem-solution', 'case-study'];
const articleStructure = structures[runCount % structures.length];

return [{
  json: {
    ...config,
    primaryKeyword,
    questionQuery,
    articleStructure,
    questionPrefix,
    expandedKeywords: expandedKeywords.join('\n'),
    usedTitles: usedTitles.join('\n'),
    usedAngles: usedAngles.join('\n'),
    usedStoryUrls: usedStoryUrls.join('\n'),
    runNumber: runCount + 1
  }
}];

// Merge all keyword research data
const items = $input.all();

function extractText(response) {
  if (!response) return '';
  if (typeof response === 'string') return response;
  if (response.text) return response.text;
  if (response.output) return typeof response.output === 'string' ? response.output : JSON.stringify(response.output);
  if (Array.isArray(response)) return JSON.stringify(response);
  return JSON.stringify(response);
}

// Parse autocomplete results
let autoKeywords = [];
let autoQuestions = [];
try {
  const kwData = items[0]?.json;
  if (Array.isArray(kwData) && kwData[1]) autoKeywords = kwData[1];
  else if (kwData?.data && Array.isArray(kwData.data)) autoKeywords = kwData.data;
} catch(e) {}
try {
  const qData = items[1]?.json;
  if (Array.isArray(qData) && qData[1]) autoQuestions = qData[1];
  else if (qData?.data && Array.isArray(qData.data)) autoQuestions = qData.data;
} catch(e) {}

// Parse Serper results
let serpResults = {};
try {
  serpResults = items[2]?.json || {};
} catch(e) {}

const paa = (serpResults.peopleAlsoAsk || []).map(p => p.question).join('\n');
const relatedSearches = (serpResults.relatedSearches || []).map(r => r.query).join('\n');
const organicTitles = (serpResults.organic || []).slice(0, 5).map(o => `${o.title} - ${o.link}`).join('\n');
const featuredSnippet = serpResults.answerBox ? `${serpResults.answerBox.title}: ${serpResults.answerBox.snippet}` : 'None';
const knowledgeGraph = serpResults.knowledgeGraph ? JSON.stringify(serpResults.knowledgeGraph) : 'None';

// Load dedup history
const staticData = $getWorkflowStaticData('global');
const history = staticData.contentHistory || [];
const usedTitles = history.slice(-4).map(h => h.title);

const config = items[0]?.json || {};

return [{
  json: {
    primaryKeyword: config.primaryKeyword || items[0]?.json?.primaryKeyword,
    questionQuery: config.questionQuery || '',
    articleStructure: config.articleStructure || 'deep-dive',
    autocompleteSuggestions: (Array.isArray(autoKeywords) ? autoKeywords : []).join('\n'),
    questionSuggestions: (Array.isArray(autoQuestions) ? autoQuestions : []).join('\n'),
    peopleAlsoAsk: paa,
    relatedSearches,
    organicResults: organicTitles,
    featuredSnippet,
    knowledgeGraph,
    usedTitles: usedTitles.join('\n'),
    config: items[0]?.json || {}
  }
}];

