// Parse GPT strategy response
const items = $input.all();

function extractText(response) {
  if (!response) return '';
  if (typeof response === 'string') return response;
  if (response.text) return response.text;
  if (response.message?.content) return response.message.content;
  if (response.output) return typeof response.output === 'string' ? response.output : JSON.stringify(response.output);
  return JSON.stringify(response);
}

const raw = extractText(items[0]?.json);

// Try to extract JSON from response
let strategy;
try {
  // Remove markdown code fences if present
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  strategy = JSON.parse(cleaned);
} catch(e) {
  // Fallback: try to find JSON in the text
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      strategy = JSON.parse(jsonMatch[0]);
    } catch(e2) {
      strategy = {
        primaryKeyword: items[0]?.json?.primaryKeyword || 'AI automation',
        articleTitle: 'AI Automation Guide for Businesses 2026',
        articleAngle: 'comprehensive guide',
        contentBrief: 'A guide to AI automation for businesses',
        targetQuestions: ['What is AI automation?'],
        secondaryKeywords: [],
        longTailKeywords: [],
        aeoStrategy: { directAnswer: '', schemaTypes: ['Article'], comparisonOpportunity: '' },
        competitorInsights: '',
        linkedinPostAngle: ''
      };
    }
  }
}

return [{ json: { ...strategy, config: items[0]?.json?.config || {} } }];

// Extract article HTML and metadata
const items = $input.all();

function extractText(response) {
  if (!response) return '';
  if (typeof response === 'string') return response;
  if (response.text) return response.text;
  if (response.message?.content) return response.message.content;
  if (response.output) return typeof response.output === 'string' ? response.output : JSON.stringify(response.output);
  return JSON.stringify(response);
}

const raw = extractText(items[0]?.json);
const parts = raw.split('|||META|||');

let articleHtml = (parts[0] || '').replace(/```html\n?/g, '').replace(/```\n?/g, '').trim();
let metadata = {};

try {
  const metaRaw = (parts[1] || '').replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const jsonMatch = metaRaw.match(/\{[\s\S]*\}/);
  if (jsonMatch) metadata = JSON.parse(jsonMatch[0]);
} catch(e) {
  metadata = {
    title: items[0]?.json?.articleTitle || 'Article',
    slug: 'article-' + Date.now(),
    metaDescription: '',
    primaryKeyword: items[0]?.json?.primaryKeyword || '',
    wordCount: articleHtml.split(/\s+/).length,
    aeoScore: 0,
    schemaTypes: ['Article']
  };
}

return [{
  json: {
    articleHtml,
    metadata,
    config: items[0]?.json?.config || {},
    strategy: items[0]?.json || {}
  }
}];

// Finalize article with quality checks
const items = $input.all();

function extractText(response) {
  if (!response) return '';
  if (typeof response === 'string') return response;
  if (response.text) return response.text;
  if (response.message?.content) return response.message.content;
  if (response.output) return typeof response.output === 'string' ? response.output : JSON.stringify(response.output);
  return JSON.stringify(response);
}

const raw = extractText(items[0]?.json);
const parts = raw.split('|||META|||');

let articleHtml = (parts[0] || '').replace(/```html\n?/g, '').replace(/```\n?/g, '').trim();
let editorMeta = {};

try {
  const metaRaw = (parts[1] || '').replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const jsonMatch = metaRaw.match(/\{[\s\S]*\}/);
  if (jsonMatch) editorMeta = JSON.parse(jsonMatch[0]);
} catch(e) {
  editorMeta = { aeoScore: 70, scores: {}, optimizations: [] };
}

// Quality gate: check for buzzwords
const buzzwords = ['leverage', 'synergy', 'cutting-edge', 'game-changer', 'revolutionize', 'disrupt', 'paradigm', 'holistic', 'robust solution'];
const foundBuzzwords = buzzwords.filter(b => articleHtml.toLowerCase().includes(b));

// Date validation
const oldDates = articleHtml.match(/\b(2023|2024|2025)\b/g) || [];

// Build article URL
const config = items[0]?.json?.config || {};
const metadata = items[0]?.json?.metadata || {};
const slug = metadata.slug || editorMeta.slug || 'article-' + Date.now();
const articleUrl = (config.articleBaseUrl || 'https://www.skynetjoe.com/blog/') + slug;

return [{
  json: {
    articleHtml,
    articleUrl,
    slug,
    aeoScore: editorMeta.aeoScore || 70,
    scores: editorMeta.scores || {},
    optimizations: editorMeta.optimizations || [],
    qualityWarnings: {
      buzzwordsFound: foundBuzzwords,
      oldDatesFound: oldDates
    },
    metadata: { ...metadata, ...editorMeta },
    config,
    strategy: items[0]?.json?.strategy || {}
  }
}];

// Build all email deliverables
const items = $input.all();

function extractText(response) {
  if (!response) return '';
  if (typeof response === 'string') return response;
  if (response.text) return response.text;
  if (response.message?.content) return response.message.content;
  if (response.output) return typeof response.output === 'string' ? response.output : JSON.stringify(response.output);
  return JSON.stringify(response);
}

const articleData = items[0]?.json || {};
const linkedinPost = extractText(items[1]?.json || '').replace(/```/g, '');
const videoScripts = extractText(items[2]?.json || '').replace(/```/g, '');

const config = articleData.config || {};
const brandColor = config.brandColor || '#13b973';
const brandColorSecondary = config.brandColorSecondary || '#8B5CF6';
const brandName = config.brandName || 'SkynetJoe Weekly AI Pulse';
const logoUrl = config.logoUrl || '';
const websiteUrl = config.websiteUrl || 'https://www.skynetjoe.com';
const senderName = config.senderName || 'Waseem Nasir';

function wrapEmail(title, content) {
  return `<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width"><title>${title}</title></head><body style="margin:0;padding:0;background:#0a0a0a;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;"><table width="100%" cellpadding="0" cellspacing="0" style="max-width:680px;margin:0 auto;"><tr><td style="background:linear-gradient(135deg,${brandColor},${brandColorSecondary});padding:32px 24px;text-align:center;"><h1 style="color:#fff;margin:0;font-size:24px;">${brandName}</h1><p style="color:rgba(255,255,255,0.8);margin:8px 0 0;font-size:14px;">by ${senderName} | <a href="${websiteUrl}" style="color:#fff;">${websiteUrl.replace('https://','')}</a></p></td></tr><tr><td style="background:#111;padding:32px 24px;color:#e0e0e0;line-height:1.7;">${content}</td></tr><tr><td style="background:#0a0a0a;padding:24px;text-align:center;color:#666;font-size:12px;"><p>SkynetJoe | AI Automation Agency</p><p><a href="${websiteUrl}" style="color:${brandColor};">${websiteUrl.replace('https://','')}</a></p></td></tr></table></body></html>`;
}

function toDocBinary(content, filename) {
  const docHtml = `<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:w="urn:schemas-microsoft-com:office:word" xmlns="http://www.w3.org/TR/REC-html40"><head><meta charset="utf-8"><style>body{font-family:Calibri,sans-serif;font-size:11pt;line-height:1.6;color:#333;}h1,h2,h3{color:#111;}table{border-collapse:collapse;width:100%;}th,td{border:1px solid #ddd;padding:8px;text-align:left;}th{background:#f5f5f5;}</style></head><body>${content}</body></html>`;
  return {
    data: Buffer.from(docHtml).toString('base64'),
    mimeType: 'application/msword',
    fileName: filename
  };
}

const date = new Date().toISOString().split('T')[0];
const title = articleData.metadata?.title || articleData.strategy?.articleTitle || 'AEO Article';
const slug = articleData.slug || 'article';

// Email 1: AEO Article
const articleEmail = wrapEmail(
  `AEO Article: ${title}`,
  `<h2 style="color:#fff;margin:0 0 16px;">This Week's AEO Article</h2><p><strong>Title:</strong> ${title}</p><p><strong>AEO Score:</strong> ${articleData.aeoScore || 'N/A'}/100</p><p><strong>Primary Keyword:</strong> ${articleData.strategy?.primaryKeyword || 'N/A'}</p><p><strong>Article URL:</strong> <a href="${articleData.articleUrl}" style="color:${brandColor};">${articleData.articleUrl}</a></p><hr style="border-color:#333;"><div>${articleData.articleHtml || '<p>Article content not available</p>'}</div>`
);

// Email 2: LinkedIn Post
const linkedinEmail = wrapEmail(
  'LinkedIn Post Draft',
  `<h2 style="color:#fff;margin:0 0 16px;">LinkedIn Post - Ready to Publish</h2><p style="color:#aaa;">Copy and paste to LinkedIn, or schedule via Buffer/Hootsuite:</p><hr style="border-color:#333;"><div style="background:#1a1a1a;padding:20px;border-radius:8px;border:1px solid #333;white-space:pre-wrap;">${linkedinPost}</div>`
);

// Email 3: Video Scripts
const videoEmail = wrapEmail(
  'Video Scripts',
  `<h2 style="color:#fff;margin:0 0 16px;">Video Scripts</h2><p style="color:#aaa;">Short-form (Reel/TikTok/Short) + Long-form (YouTube):</p><hr style="border-color:#333;"><div style="white-space:pre-wrap;">${videoScripts}</div>`
);

// Email 4: Instructions
const instructionsEmail = wrapEmail(
  'Publishing Instructions',
  `<h2 style="color:#fff;margin:0 0 16px;">Publishing Checklist</h2><ol style="color:#e0e0e0;"><li><strong>Blog Article:</strong> Copy the .html attachment → paste into WordPress editor → publish at ${articleData.articleUrl}</li><li><strong>LinkedIn:</strong> Copy the LinkedIn post → paste into LinkedIn → add relevant image → publish</li><li><strong>Video Scripts:</strong> Record short-form with Teleprompter app → upload to Instagram Reels, TikTok, YouTube Shorts. Record long-form for YouTube.</li><li><strong>Schema:</strong> Ensure FAQPage schema is added to the blog post (use Yoast or manual JSON-LD)</li><li><strong>Internal Links:</strong> Add links from this article to 2-3 relevant service pages</li><li><strong>Social Sharing:</strong> Share the blog URL on Twitter, LinkedIn, relevant communities</li></ol><p style="color:#aaa;">AEO Score: ${articleData.aeoScore || 'N/A'}/100 | Run #${articleData.config?.runNumber || '?'} | ${date}</p>`
);

// Build output items with binary attachments
const outputs = [
  {
    json: { subject: `[SkynetJoe AEO] Article: ${title}`, html: articleEmail, to: config.recipientEmail },
    binary: {
      'article_html': {
        data: Buffer.from(articleData.articleHtml || '').toString('base64'),
        mimeType: 'text/html',
        fileName: `skynetjoe-aeo-article-${date}.html`
      },
      'article_doc': toDocBinary(articleData.articleHtml || '', `skynetjoe-aeo-article-${date}.doc`)
    }
  },
  {
    json: { subject: `[SkynetJoe AEO] LinkedIn Post: ${title}`, html: linkedinEmail, to: config.recipientEmail },
    binary: {
      'linkedin_doc': toDocBinary(`<h1>LinkedIn Post</h1><div style="white-space:pre-wrap;">${linkedinPost}</div>`, `skynetjoe-linkedin-post-${date}.doc`)
    }
  },
  {
    json: { subject: `[SkynetJoe AEO] Video Scripts: ${title}`, html: videoEmail, to: config.recipientEmail },
    binary: {
      'scripts_doc': toDocBinary(`<h1>Video Scripts</h1><div style="white-space:pre-wrap;">${videoScripts}</div>`, `skynetjoe-video-scripts-${date}.doc`)
    }
  },
  {
    json: { subject: `[SkynetJoe AEO] Publishing Instructions`, html: instructionsEmail, to: config.recipientEmail }
  }
];

return outputs;

// Save content history for dedup
const items = $input.all();
const staticData = $getWorkflowStaticData('global');

if (!staticData.contentHistory) staticData.contentHistory = [];

const firstItem = items[0]?.json || {};
const config = firstItem.config || {};
const strategy = firstItem.strategy || {};
const metadata = firstItem.metadata || {};

staticData.contentHistory.push({
  date: new Date().toISOString().split('T')[0],
  keyword: strategy.primaryKeyword || '',
  title: metadata.title || strategy.articleTitle || '',
  slug: firstItem.slug || '',
  angle: strategy.articleAngle || '',
  articleStructure: config.articleStructure || '',
  aeoScore: firstItem.aeoScore || 0,
  storyUrls: [],
  runNumber: config.runNumber || 0
});

// Keep last 52 entries
if (staticData.contentHistory.length > 52) {
  staticData.contentHistory = staticData.contentHistory.slice(-52);
}

return [{ json: { saved: true, historyLength: staticData.contentHistory.length } }];

// MANUAL: Reset all content history
const staticData = $getWorkflowStaticData('global');
staticData.contentHistory = [];
return [{ json: { message: 'Content history cleared', timestamp: new Date().toISOString() } }];
